protected void new()
{
    super(classStr(HDG_ExcelUploadService), methodStr(HDG_ExcelUploadService, processExcel), SysOperationExecutionMode::Synchronous);
}

public static void main(Args _args)
{
    HDG_ExcelUploadController controller = new HDG_ExcelUploadController();

    controller.parmArgs(_args);
    controller.showBatchTab(false);
    controller.startOperation();

    HDG_AssetTable assetTable = _args.record() as HDG_AssetTable;

    if (_args && _args.record() && FormDataUtil::getFormDataSource(assetTable))
    {
        FormDataSource fds = FormDataUtil::getFormDataSource(assetTable);
        fds.research(true);
    }
}

public boolean validateParameters()
{
    boolean isValid = super();

    HDG_ExcelUploadContract contract = this.getDataContractObject() as HDG_ExcelUploadContract;

    if (!contract || !contract.parmFileUrl())
    {
        isValid = checkFailed("@SYS97287");
    }

    return isValid;
}
